import './TimePicker.scss';

import { Icon } from ':components/Icon';
import { TextField } from ':components/TextField';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React, { useRef } from 'react';

import type { TimePickerProps } from './TimePicker.types';

export const TimePicker: React.FC<TimePickerProps> = ({
	className,
	onChange,
	value,
	disabled = false,
	error,
	errorMessage,
	onBlur,
	dataTestId = 'TimePicker',
}) => {
	const minutesRef = useRef<HTMLInputElement | null>(null);

	const { hours, minutes } = value;

	// ---------- helpers: чистые функции и guard-clauses ----------
	const sanitizeDigits = (input: string): string => input.replace(/\D/g, '');

	const inRange = (num: number, range: [number, number]): boolean => num >= range[0] && num < range[1];

	const normalizeOnBlur = (val: string): string => {
		if (val.length === 1) return `0${val}`;
		if (val.length === 0) return '00';
		return val;
	};

	const handleInputChange = async (
		event: React.ChangeEvent<HTMLInputElement>,
		updateState: (v: string) => void,
		range: [number, number],
		onComplete?: () => void,
	) => {
		const raw = event.target.value;
		const digits = sanitizeDigits(raw);

		// авто-переход при шаблоне '00x'
		if (raw.slice(0, 2) === '00') {
			updateState(`0${raw.slice(2, 3)}`);
			onComplete?.();
			return;
		}

		if (digits.length === 0) {
			updateState('');
			return;
		}

		if (digits.length === 1) {
			const n = Number.parseInt(digits, 10);
			if (inRange(n, range)) {
				updateState(digits);
			}
			return;
		}

		const last2 = digits.slice(-2);
		const n = Number.parseInt(last2, 10);
		if (inRange(n, range)) {
			updateState(last2);
			// Деферим onComplete, чтобы родитель успел применить setState
			if (onComplete) {
				setTimeout(() => onComplete(), 0);
			}
		}
	};

	const handleBlur = (val: string, updateState: (v: string) => void) => {
		updateState(normalizeOnBlur(val));
	};

	return (
		<div className={classNames('timepicker', className)} data-testid={dataTestId}>
			<Icon className="timepicker__icon" iconName={Icons.Clock} />
			<TextField
				data-testid={dataTestId + '-hours'}
				className="timepicker__input"
				value={hours}
				placeholder={'00'}
				error={error}
				disabled={disabled}
				helperText={errorMessage}
				onChange={event => {
					void handleInputChange(
						event,
						val => {
							onChange?.({ hours: val, minutes });
						},
						[0, 24],
						() => {
							if (minutesRef.current) {
								minutesRef.current?.focus();
							}
						},
					);
				}}
				onBlur={() =>
					handleBlur(hours, val => {
						onChange?.({ hours: val, minutes });
					})
				}
			/>
			<span className="timepicker__separator">:</span>
			<TextField
				data-testid={dataTestId + '-minutes'}
				className="timepicker__input"
				value={minutes}
				placeholder={'00'}
				ref={minutesRef}
				error={error}
				disabled={disabled}
				onChange={event => {
					void handleInputChange(
						event,
						val => {
							onChange?.({ hours, minutes: val });
						},

						[0, 60],
						() => {
							event.target.blur();
						},
					);
				}}
				onBlur={() =>
					handleBlur(minutes, val => {
						onChange?.({ hours, minutes: val });
						onBlur?.(value);
					})
				}
			/>
		</div>
	);
};
